window.KJV1769_STRONG_BOOKS["Mic"] = {"osis":"Mic","book":"미가","verses":{"1:1":{"text":"The word of the LORD that came to Micah the Morasthite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem.","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H4318","that came to Micah",21,39],["H4183","the Morasthite",40,54],["H3117","in the days",55,66],["H3147","of Jotham",67,76],["H0271","Ahaz",78,82],["H3169","and Hezekiah",84,96],["H4428","kings",98,103],["H3063","of Judah",104,112],["H2372","which he saw",114,126],["H8111","concerning Samaria",127,145],["H3389","and Jerusalem",146,159]]},"1:2":{"text":"Hear, all ye people; hearken, O earth, and all that therein is: and let the Lord GOD be witness against you, the Lord from his holy temple.","words":[["H8085","Hear",0,4],["H5971","all ye people",6,19],["H7181","hearken",21,28],["H0776","O earth",30,37],["H4393","and all that therein",39,59],["H0136","is: and let the Lord",60,80],["H3069","GOD",81,84],["H5707","be witness",85,95],["H0136","against you, the Lord",96,117],["H6944","from his holy",118,131],["H1964","temple",132,138]]},"1:3":{"text":"For, behold, the LORD cometh forth out of his place, and will come down, and tread upon the high places of the earth.","words":[["H3068","For, behold, the LORD",0,21],["H3318","cometh forth",22,34],["H4725","out of his place",35,51],["H3381","and will come down",53,71],["H1869","and tread",73,82],["H1116","upon the high places",83,103],["H0776","of the earth",104,116]]},"1:4":{"text":"And the mountains shall be molten under him, and the valleys shall be cleft, as wax before the fire, and as the waters that are poured down a steep place.","words":[["H2022","And the mountains",0,17],["H4549","shall be molten",18,33],["H6010","under him, and the valleys",34,60],["H1234","shall be cleft",61,75],["H1749","as wax",77,83],["H6440","before",84,90],["H0784","the fire",91,99],["H4325","and as the waters",101,118],["H5064","that are poured",119,134],["H4174","down a steep place",135,153]]},"1:5":{"text":"For the transgression of Jacob is all this, and for the sins of the house of Israel. What is the transgression of Jacob? is it not Samaria? and what are the high places of Judah? are they not Jerusalem?","words":[["H6588","For the transgression",0,21],["H3290","of Jacob",22,30],["H2403","is all this, and for the sins",31,60],["H1004","of the house",61,73],["H3478","of Israel",74,83],["H6588","What is the transgression",85,110],["H3290","of Jacob",111,119],["H8111","is it not Samaria",121,138],["H1116","and what are the high places",140,168],["H3063","of Judah",169,177],["H3389","are they not Jerusalem",179,201]]},"1:6":{"text":"Therefore I will make Samaria as an heap of the field, and as plantings of a vineyard: and I will pour down the stones thereof into the valley, and I will discover the foundations thereof.","words":[["H7760","Therefore I will make",0,21],["H8111","Samaria",22,29],["H5856","as an heap",30,40],["H7704","of the field",41,53],["H4302","and as plantings",55,71],["H3754","of a vineyard",72,85],["H5064","and I will pour down",87,107],["H0068","the stones",108,118],["H1516","thereof into the valley",119,142],["H1540","and I will discover",144,163],["H3247","the foundations",164,179]]},"1:7":{"text":"And all the graven images thereof shall be beaten to pieces, and all the hires thereof shall be burned with the fire, and all the idols thereof will I lay desolate: for she gathered it of the hire of an harlot, and they shall return to the hire of an harlot.","words":[["H6456","And all the graven images",0,25],["H3807","thereof shall be beaten to pieces",26,59],["H0868","and all the hires",61,78],["H8313","thereof shall be burned",79,102],["H0784","with the fire",103,116],["H6091","and all the idols",118,135],["H7760","thereof will I lay",136,154],["H8077","desolate",155,163],["H6908","for she gathered",165,181],["H0868","it of the hire",182,196],["H2181","of an harlot",197,209],["H7725","and they shall return",211,232],["H0868","to the hire",233,244],["H2181","of an harlot",245,257]]},"1:8":{"text":"Therefore I will wail and howl, I will go stripped and naked: I will make a wailing like the dragons, and mourning as the owls.","words":[["H5594","Therefore I will wail",0,21],["H3213","and howl",22,30],["H3212","I will go",32,41],["H7758","stripped",42,50],["H7758","stripped",42,50],["H6174","and naked",51,60],["H6213","I will make",62,73],["H4553","a wailing",74,83],["H8577","like the dragons",84,100],["H0060","and mourning",102,114],["H1323","as the owls",115,126],["H3284","as the owls",115,126]]},"1:9":{"text":"For her wound is incurable; for it is come unto Judah; he is come unto the gate of my people, even to Jerusalem.","words":[["H4347","For her wound",0,13],["H0605","is incurable",14,26],["H0935","for it is come",28,42],["H3063","unto Judah",43,53],["H5060","he is come",55,65],["H8179","unto the gate",66,79],["H5971","of my people",80,92],["H3389","even to Jerusalem",94,111]]},"1:10":{"text":"Declare ye it not at Gath, weep ye not at all: in the house of Aphrah roll thyself in the dust.","words":[["H5046","Declare",0,7],["H1661","ye it not at Gath",8,25],["H1058","weep",27,31],["H1058","ye not at all",32,45],["H1036","in the house of Aphrah",47,69],["H6428","roll",70,74],["H6428","roll",70,74],["H6083","thyself in the dust",75,94]]},"1:11":{"text":"Pass ye away, thou inhabitant of Saphir, having thy shame naked: the inhabitant of Zaanan came not forth in the mourning of Bethezel; he shall receive of you his standing.","words":[["H5674","Pass ye away",0,12],["H3427","thou inhabitant",14,29],["H8208","of Saphir",30,39],["H1322","having thy shame",41,57],["H6181","naked",58,63],["H3427","the inhabitant",65,79],["H6630","of Zaanan",80,89],["H3318","came not forth",90,104],["H4553","in the mourning",105,120],["H1018","of Bethezel",121,132],["H3947","he shall receive",134,150],["H5979","of you his standing",151,170]]},"1:12":{"text":"For the inhabitant of Maroth waited carefully for good: but evil came down from the LORD unto the gate of Jerusalem.","words":[["H3427","For the inhabitant",0,18],["H4796","of Maroth",19,28],["H2342","waited carefully",29,45],["H2896","for good",46,54],["H7451","but evil",56,64],["H3381","came down",65,74],["H3068","from the LORD",75,88],["H8179","unto the gate",89,102],["H3389","of Jerusalem",103,115]]},"1:13":{"text":"O thou inhabitant of Lachish, bind the chariot to the swift beast: she is the beginning of the sin to the daughter of Zion: for the transgressions of Israel were found in thee.","words":[["H3427","O thou inhabitant",0,17],["H3923","of Lachish",18,28],["H7573","bind",30,34],["H4818","the chariot",35,46],["H7409","to the swift beast",47,65],["H7225","she is the beginning",67,87],["H2403","of the sin",88,98],["H1323","to the daughter",99,114],["H6726","of Zion",115,122],["H6588","for the transgressions",124,146],["H3478","of Israel",147,156],["H4672","were found",157,167]]},"1:14":{"text":"Therefore shalt thou give presents to Moreshethgath: the houses of Achzib shall be a lie to the kings of Israel.","words":[["H5414","Therefore shalt thou give",0,25],["H7964","presents",26,34],["H4182","to Moreshethgath",35,51],["H1004","the houses",53,63],["H0392","of Achzib",64,73],["H0391","shall be a lie",74,88],["H4428","to the kings",89,101],["H3478","of Israel",102,111]]},"1:15":{"text":"Yet will I bring an heir unto thee, O inhabitant of Mareshah: he shall come unto Adullam the glory of Israel.","words":[["H0935","Yet will I bring",0,16],["H3423","an heir",17,24],["H3427","unto thee, O inhabitant",25,48],["H4762","of Mareshah",49,60],["H0935","he shall come",62,75],["H5725","unto Adullam",76,88],["H3519","the glory",89,98],["H3478","of Israel",99,108]]},"1:16":{"text":"Make thee bald, and poll thee for thy delicate children; enlarge thy baldness as the eagle; for they are gone into captivity from thee.","words":[["H7139","Make thee bald",0,14],["H1494","and poll",16,24],["H8588","thee for thy delicate",25,46],["H1121","children",47,55],["H7337","enlarge",57,64],["H7144","thy baldness",65,77],["H5404","as the eagle",78,90],["H1540","for they are gone into captivity",92,124]]},"2:1":{"text":"Woe to them that devise iniquity, and work evil upon their beds! when the morning is light, they practise it, because it is in the power of their hand.","words":[["H1945","Woe",0,3],["H2803","to them that devise",4,23],["H0205","iniquity",24,32],["H6466","and work",34,42],["H7451","evil",43,47],["H4904","upon their beds",48,63],["H1242","when the morning",65,81],["H0216","is light",82,90],["H6213","they practise",92,105],["H3426","it, because it is",106,123],["H0410","in the power",124,136],["H3027","of their hand",137,150]]},"2:2":{"text":"And they covet fields, and take them by violence; and houses, and take them away: so they oppress a man and his house, even a man and his heritage.","words":[["H2530","And they covet",0,14],["H7704","fields",15,21],["H1497","and take them by violence",23,48],["H1004","and houses",50,60],["H5375","and take them away",62,80],["H6231","so they oppress",82,97],["H1397","a man",98,103],["H1004","and his house",104,117],["H0376","even a man",119,129],["H5159","and his heritage",130,146]]},"2:3":{"text":"Therefore thus saith the LORD; Behold, against this family do I devise an evil, from which ye shall not remove your necks; neither shall ye go haughtily: for this time is evil.","words":[["H0559","Therefore thus saith",0,20],["H3068","the LORD",21,29],["H4940","Behold, against this family",31,58],["H2803","do I devise",59,70],["H7451","an evil",71,78],["H4185","from which ye shall not remove",80,110],["H6677","your necks",111,121],["H3212","neither shall ye go",123,142],["H7317","haughtily",143,152],["H6256","for this time",154,167],["H7451","is evil",168,175]]},"2:4":{"text":"In that day shall one take up a parable against you, and lament with a doleful lamentation, and say, We be utterly spoiled: he hath changed the portion of my people: how hath he removed it from me! turning away he hath divided our fields.","words":[["H3117","In that day",0,11],["H5375","shall one take up",12,29],["H4912","a parable",30,39],["H5091","against you, and lament",40,63],["H5093","with a doleful",64,78],["H5092","lamentation",79,90],["H0559","and say",92,99],["H7703","We be utterly",101,114],["H7703","spoiled",115,122],["H4171","he hath changed",124,139],["H2506","the portion",140,151],["H5971","of my people",152,164],["H4185","how hath he removed",166,185],["H7725","it from me! turning away",186,210],["H2505","he hath divided",211,226],["H7704","our fields",227,237]]},"2:5":{"text":"Therefore thou shalt have none that shall cast a cord by lot in the congregation of the LORD.","words":[["H7993","Therefore thou shalt have none that shall cast",0,46],["H2256","a cord",47,53],["H1486","by lot",54,60],["H6951","in the congregation",61,80],["H3068","of the LORD",81,92]]},"2:6":{"text":"Prophesy ye not, say they to them that prophesy: they shall not prophesy to them, that they shall not take shame.","words":[["H5197","Prophesy",0,8],["H5197","ye not, say they to them that prophesy",9,47],["H5197","they shall not prophesy",49,72],["H5253","to them, that they shall not take",73,106],["H3639","shame",107,112]]},"2:7":{"text":"O thou that art named the house of Jacob, is the spirit of the LORD straitened? are these his doings? do not my words do good to him that walketh uprightly?","words":[["H0559","O thou that art named",0,21],["H1004","the house",22,31],["H3290","of Jacob",32,40],["H7307","is the spirit",42,55],["H3068","of the LORD",56,67],["H7114","straitened",68,78],["H4611","are these his doings",80,100],["H1697","do not my words",102,117],["H3190","do good",118,125],["H1980","to him that walketh",126,145],["H3477","uprightly",146,155]]},"2:8":{"text":"Even of late my people is risen up as an enemy: ye pull off the robe with the garment from them that pass by securely as men averse from war.","words":[["H0865","Even of late",0,12],["H5971","my people",13,22],["H6965","is risen up",23,34],["H0341","as an enemy",35,46],["H6584","ye pull off",48,59],["H0145","the robe",60,68],["H4136","with",69,73],["H8008","the garment",74,85],["H5674","from them that pass",86,105],["H0983","by securely",106,117],["H7725","as men averse",118,131],["H4421","from war",132,140]]},"2:9":{"text":"The women of my people have ye cast out from their pleasant houses; from their children have ye taken away my glory for ever.","words":[["H0802","The women",0,9],["H5971","of my people",10,22],["H1644","have ye cast out",23,39],["H8588","from their pleasant",40,59],["H1004","houses",60,66],["H5768","from their children",68,87],["H3947","have ye taken away",88,106],["H1926","my glory",107,115],["H5769","for ever",116,124]]},"2:10":{"text":"Arise ye, and depart; for this is not your rest: because it is polluted, it shall destroy you, even with a sore destruction.","words":[["H6965","Arise",0,5],["H3212","ye, and depart",6,20],["H4496","for this is not your rest",22,47],["H2930","because it is polluted",49,71],["H2254","it shall destroy",73,89],["H4834","you, even with a sore",90,111],["H2256","destruction",112,123]]},"2:11":{"text":"If a man walking in the spirit and falsehood do lie, saying, I will prophesy unto thee of wine and of strong drink; he shall even be the prophet of this people.","words":[["H3863","If",0,2],["H0376","a man",3,8],["H1980","walking",9,16],["H7307","in the spirit",17,30],["H8267","and falsehood",31,44],["H3576","do lie",45,51],["H5197","saying, I will prophesy",53,76],["H3196","unto thee of wine",77,94],["H7941","and of strong drink",95,114],["H5197","he shall even be the prophet",116,144],["H5971","of this people",145,159]]},"2:12":{"text":"I will surely assemble, O Jacob, all of thee; I will surely gather the remnant of Israel; I will put them together as the sheep of Bozrah, as the flock in the midst of their fold: they shall make great noise by reason of the multitude of men.","words":[["H0622","I will surely",0,13],["H0622","assemble",14,22],["H3290","O Jacob",24,31],["H6908","all of thee; I will surely",33,59],["H6908","gather",60,66],["H7611","the remnant",67,78],["H3478","of Israel",79,88],["H7760","I will put",90,100],["H3162","them together",101,114],["H6629","as the sheep",115,127],["H1223","of Bozrah",128,137],["H1224","of Bozrah",128,137],["H5739","as the flock",139,151],["H8432","in the midst",152,164],["H1699","of their fold",165,178],["H1949","they shall make great noise",180,207],["H0120","by reason of the multitude of men",208,241]]},"2:13":{"text":"The breaker is come up before them: they have broken up, and have passed through the gate, and are gone out by it: and their king shall pass before them, and the LORD on the head of them.","words":[["H6555","The breaker",0,11],["H5927","is come up",12,22],["H6440","before",23,29],["H6555","them: they have broken up",30,55],["H5674","and have passed through",57,80],["H8179","the gate",81,89],["H3318","and are gone out",91,107],["H4428","by it: and their king",108,129],["H5674","shall pass",130,140],["H6440","before",141,147],["H3068","them, and the LORD",148,166],["H7218","on the head",167,178]]},"3:1":{"text":"And I said, Hear, I pray you, O heads of Jacob, and ye princes of the house of Israel; Is it not for you to know judgment?","words":[["H0559","And I said",0,10],["H8085","Hear",12,16],["H7218","I pray you, O heads",18,37],["H3290","of Jacob",38,46],["H7101","and ye princes",48,62],["H1004","of the house",63,75],["H3478","of Israel",76,85],["H3045","Is it not for you to know",87,112],["H4941","judgment",113,121]]},"3:2":{"text":"Who hate the good, and love the evil; who pluck off their skin from off them, and their flesh from off their bones;","words":[["H8130","Who hate",0,8],["H2896","the good",9,17],["H0157","and love",19,27],["H7451","the evil",28,36],["H1497","who pluck off",38,51],["H5785","their skin",52,62],["H7607","from off them, and their flesh",63,93],["H6106","from off their bones",94,114]]},"3:3":{"text":"Who also eat the flesh of my people, and flay their skin from off them; and they break their bones, and chop them in pieces, as for the pot, and as flesh within the caldron.","words":[["H0398","Who also eat",0,12],["H7607","the flesh",13,22],["H5971","of my people",23,35],["H6584","and flay",37,45],["H5785","their skin",46,56],["H6476","from off them; and they break",57,86],["H6106","their bones",87,98],["H6566","and chop them in pieces",100,123],["H5518","as for the pot",125,139],["H1320","and as flesh",141,153],["H8432","within",154,160],["H7037","the caldron",161,172]]},"3:4":{"text":"Then shall they cry unto the LORD, but he will not hear them: he will even hide his face from them at that time, as they have behaved themselves ill in their doings.","words":[["H2199","Then shall they cry",0,19],["H3068","unto the LORD",20,33],["H6030","but he will not hear",35,55],["H5641","them: he will even hide",56,79],["H6440","his face",80,88],["H6256","from them at that time",89,111],["H7489","as they have behaved themselves ill",113,148],["H4611","in their doings",149,164]]},"3:5":{"text":"Thus saith the LORD concerning the prophets that make my people err, that bite with their teeth, and cry, Peace; and he that putteth not into their mouths, they even prepare war against him.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H5030","concerning the prophets",20,43],["H5971","that make my people",44,63],["H8582","err",64,67],["H5391","that bite",69,78],["H8127","with their teeth",79,95],["H7121","and cry",97,104],["H7965","Peace",106,111],["H5414","and he that putteth",113,132],["H6310","not into their mouths",133,154],["H6942","they even prepare",156,173],["H4421","war",174,177]]},"3:6":{"text":"Therefore night shall be unto you, that ye shall not have a vision; and it shall be dark unto you, that ye shall not divine; and the sun shall go down over the prophets, and the day shall be dark over them.","words":[["H3915","Therefore night",0,15],["H2377","shall be unto you, that ye shall not have a vision",16,66],["H2821","and it shall be dark",68,88],["H2821","and it shall be dark",68,88],["H7080","unto you, that ye shall not divine",89,123],["H8121","and the sun",125,136],["H0935","shall go down",137,150],["H5030","over the prophets",151,168],["H3117","and the day",170,181],["H6937","shall be dark",182,195]]},"3:7":{"text":"Then shall the seers be ashamed, and the diviners confounded: yea, they shall all cover their lips; for there is no answer of God.","words":[["H2374","Then shall the seers",0,20],["H0954","be ashamed",21,31],["H7080","and the diviners",33,49],["H2659","confounded",50,60],["H5844","yea, they shall all cover",62,87],["H8222","their lips",88,98],["H4617","for there is no answer",100,122],["H0430","of God",123,129]]},"3:8":{"text":"But truly I am full of power by the spirit of the LORD, and of judgment, and of might, to declare unto Jacob his transgression, and to Israel his sin.","words":[["H0199","But truly",0,9],["H4390","I am full",10,19],["H3581","of power",20,28],["H7307","by the spirit",29,42],["H3068","of the LORD",43,54],["H4941","and of judgment",56,71],["H1369","and of might",73,85],["H5046","to declare",87,97],["H3290","unto Jacob",98,108],["H6588","his transgression",109,126],["H3478","and to Israel",128,141],["H2403","his sin",142,149]]},"3:9":{"text":"Hear this, I pray you, ye heads of the house of Jacob, and princes of the house of Israel, that abhor judgment, and pervert all equity.","words":[["H8085","Hear",0,4],["H7218","this, I pray you, ye heads",5,31],["H1004","of the house",32,44],["H3290","of Jacob",45,53],["H7101","and princes",55,66],["H1004","of the house",67,79],["H3478","of Israel",80,89],["H8581","that abhor",91,101],["H4941","judgment",102,110],["H6140","and pervert",112,123],["H3477","all equity",124,134]]},"3:10":{"text":"They build up Zion with blood, and Jerusalem with iniquity.","words":[["H1129","They build up",0,13],["H6726","Zion",14,18],["H1818","with blood",19,29],["H3389","and Jerusalem",31,44],["H5766","with iniquity",45,58]]},"3:11":{"text":"The heads thereof judge for reward, and the priests thereof teach for hire, and the prophets thereof divine for money: yet will they lean upon the LORD, and say, Is not the LORD among us? none evil can come upon us.","words":[["H7218","The heads",0,9],["H8199","thereof judge",10,23],["H7810","for reward",24,34],["H3548","and the priests",36,51],["H3384","thereof teach",52,65],["H4242","for hire",66,74],["H5030","and the prophets",76,92],["H7080","thereof divine",93,107],["H3701","for money",108,117],["H8172","yet will they lean",119,137],["H3068","upon the LORD",138,151],["H0559","and say",153,160],["H3068","Is not the LORD",162,177],["H7130","among",178,183],["H7451","us? none evil",184,197],["H0935","can come",198,206]]},"3:12":{"text":"Therefore shall Zion for your sake be plowed as a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of the forest.","words":[["H6726","Therefore shall Zion",0,20],["H1558","for your sake",21,34],["H2790","be plowed",35,44],["H7704","as a field",45,55],["H3389","and Jerusalem",57,70],["H5856","shall become heaps",71,89],["H2022","and the mountain",91,107],["H1004","of the house",108,120],["H1116","as the high places",121,139],["H3293","of the forest",140,153]]},"4:1":{"text":"But in the last days it shall come to pass, that the mountain of the house of the LORD shall be established in the top of the mountains, and it shall be exalted above the hills; and people shall flow unto it.","words":[["H0319","But in the last",0,15],["H3117","days",16,20],["H2022","it shall come to pass, that the mountain",21,61],["H1004","of the house",62,74],["H3068","of the LORD",75,86],["H3559","shall be established",87,107],["H7218","in the top",108,118],["H2022","of the mountains",119,135],["H5375","and it shall be exalted",137,160],["H1389","above the hills",161,176],["H5971","and people",178,188],["H5102","shall flow",189,199]]},"4:2":{"text":"And many nations shall come, and say, Come, and let us go up to the mountain of the LORD, and to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for the law shall go forth of Zion, and the word of the LORD from Jerusalem.","words":[["H7227","And many",0,8],["H1471","nations",9,16],["H1980","shall come",17,27],["H0559","and say",29,36],["H3212","Come",38,42],["H5927","and let us go up",44,60],["H2022","to the mountain",61,76],["H3068","of the LORD",77,88],["H1004","and to the house",90,106],["H0430","of the God",107,117],["H3290","of Jacob",118,126],["H3384","and he will teach",128,145],["H1870","us of his ways",146,160],["H3212","and we will walk",162,178],["H0734","in his paths",179,191],["H8451","for the law",193,204],["H3318","shall go forth",205,219],["H6726","of Zion",220,227],["H1697","and the word",229,241],["H3068","of the LORD",242,253],["H3389","from Jerusalem",254,268]]},"4:3":{"text":"And he shall judge among many people, and rebuke strong nations afar off; and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up a sword against nation, neither shall they learn war any more.","words":[["H8199","And he shall judge",0,18],["H7227","among many",19,29],["H5971","people",30,36],["H3198","and rebuke",38,48],["H6099","strong",49,55],["H1471","nations",56,63],["H7350","afar off",64,72],["H3807","and they shall beat",74,93],["H2719","their swords",94,106],["H0855","into plowshares",107,122],["H2595","and their spears",124,140],["H4211","into pruninghooks",141,158],["H1471","nation",160,166],["H5375","shall not lift up",167,184],["H2719","a sword",185,192],["H1471","against nation",193,207],["H3925","neither shall they learn",209,233],["H4421","war",234,237]]},"4:4":{"text":"But they shall sit every man under his vine and under his fig tree; and none shall make them afraid: for the mouth of the LORD of hosts hath spoken it.","words":[["H3427","But they shall sit",0,18],["H0376","every man",19,28],["H1612","under his vine",29,43],["H8384","and under his fig tree",44,66],["H2729","and none shall make them afraid",68,99],["H6310","for the mouth",101,114],["H3068","of the LORD",115,126],["H6635","of hosts",127,135],["H1696","hath spoken",136,147]]},"4:5":{"text":"For all people will walk every one in the name of his god, and we will walk in the name of the LORD our God for ever and ever.","words":[["H5971","For all people",0,14],["H3212","will walk",15,24],["H0376","every one",25,34],["H8034","in the name",35,46],["H0430","of his god",47,57],["H3212","and we will walk",59,75],["H8034","in the name",76,87],["H3068","of the LORD",88,99],["H0430","our God",100,107],["H5769","for ever",108,116],["H5703","and ever",117,125]]},"4:6":{"text":"In that day, saith the LORD, will I assemble her that halteth, and I will gather her that is driven out, and her that I have afflicted;","words":[["H3117","In that day",0,11],["H5002","saith",13,18],["H3068","the LORD",19,27],["H0622","will I assemble",29,44],["H6760","her that halteth",45,61],["H6908","and I will gather",63,80],["H5080","her that is driven out",81,103],["H7489","and her that I have afflicted",105,134]]},"4:7":{"text":"And I will make her that halted a remnant, and her that was cast far off a strong nation: and the LORD shall reign over them in mount Zion from henceforth, even for ever.","words":[["H7760","And I will make",0,15],["H6760","her that halted",16,31],["H7611","a remnant",32,41],["H1972","and her that was cast far off",43,72],["H6099","a strong",73,81],["H1471","nation",82,88],["H3068","and the LORD",90,102],["H4427","shall reign",103,114],["H2022","over them in mount",115,133],["H6726","Zion",134,138],["H5704","from henceforth, even for",139,164],["H5769","ever",165,169]]},"4:8":{"text":"And thou, O tower of the flock, the strong hold of the daughter of Zion, unto thee shall it come, even the first dominion; the kingdom shall come to the daughter of Jerusalem.","words":[["H4026","And thou, O tower",0,17],["H5739","of the flock",18,30],["H4029","of the flock",18,30],["H6076","the strong hold",32,47],["H1323","of the daughter",48,63],["H6726","of Zion",64,71],["H0857","unto thee shall it come",73,96],["H7223","even the first",98,112],["H4475","dominion",113,121],["H4467","the kingdom",123,134],["H0935","shall come",135,145],["H1323","to the daughter",146,161],["H3389","of Jerusalem",162,174]]},"4:9":{"text":"Now why dost thou cry out aloud? is there no king in thee? is thy counsellor perished? for pangs have taken thee as a woman in travail.","words":[["H7321","Now why dost thou cry",0,21],["H7452","out aloud",22,31],["H4428","is there no king",33,49],["H3289","in thee? is thy counsellor",50,76],["H0006","perished",77,85],["H2427","for pangs",87,96],["H2388","have taken",97,107],["H3205","thee as a woman in travail",108,134]]},"4:10":{"text":"Be in pain, and labour to bring forth, O daughter of Zion, like a woman in travail: for now shalt thou go forth out of the city, and thou shalt dwell in the field, and thou shalt go even to Babylon; there shalt thou be delivered; there the LORD shall redeem thee from the hand of thine enemies.","words":[["H2342","Be in pain",0,10],["H1518","and labour to bring forth",12,37],["H1323","O daughter",39,49],["H6726","of Zion",50,57],["H3205","like a woman in travail",59,82],["H3318","for now shalt thou go forth",84,111],["H7151","out of the city",112,127],["H7931","and thou shalt dwell",129,149],["H7704","in the field",150,162],["H0935","and thou shalt go",164,181],["H0894","even to Babylon",182,197],["H5337","there shalt thou be delivered",199,228],["H3068","there the LORD",230,244],["H1350","shall redeem",245,257],["H3709","thee from the hand",258,276],["H0341","of thine enemies",277,293]]},"4:11":{"text":"Now also many nations are gathered against thee, that say, Let her be defiled, and let our eye look upon Zion.","words":[["H7227","Now also many",0,13],["H1471","nations",14,21],["H0622","are gathered",22,34],["H0559","against thee, that say",35,57],["H2610","Let her be defiled",59,77],["H5869","and let our eye",79,94],["H2372","look",95,99],["H6726","upon Zion",100,109]]},"4:12":{"text":"But they know not the thoughts of the LORD, neither understand they his counsel: for he shall gather them as the sheaves into the floor.","words":[["H3045","But they know",0,13],["H4284","not the thoughts",14,30],["H3068","of the LORD",31,42],["H0995","neither understand",44,62],["H6098","they his counsel",63,79],["H6908","for he shall gather",81,100],["H5995","them as the sheaves",101,120],["H1637","into the floor",121,135]]},"4:13":{"text":"Arise and thresh, O daughter of Zion: for I will make thine horn iron, and I will make thy hoofs brass: and thou shalt beat in pieces many people: and I will consecrate their gain unto the LORD, and their substance unto the Lord of the whole earth.","words":[["H6965","Arise",0,5],["H1758","and thresh",6,16],["H1323","O daughter",18,28],["H6726","of Zion",29,36],["H7760","for I will make",38,53],["H7161","thine horn",54,64],["H1270","iron",65,69],["H7760","and I will make",71,86],["H6541","thy hoofs",87,96],["H5154","brass",97,102],["H1854","and thou shalt beat in pieces",104,133],["H7227","many",134,138],["H5971","people",139,145],["H2763","and I will consecrate",147,168],["H1215","their gain",169,179],["H3068","unto the LORD",180,193],["H2428","and their substance",195,214],["H0113","unto the Lord",215,228],["H0776","of the whole earth",229,247]]},"5:1":{"text":"Now gather thyself in troops, O daughter of troops: he hath laid siege against us: they shall smite the judge of Israel with a rod upon the cheek.","words":[["H1413","Now gather",0,10],["H1416","thyself in troops",11,28],["H1323","O daughter",30,40],["H1416","of troops",41,50],["H7760","he hath laid",52,64],["H4692","siege",65,70],["H5221","against us: they shall smite",71,99],["H8199","the judge",100,109],["H3478","of Israel",110,119],["H7626","with a rod",120,130],["H3895","upon the cheek",131,145]]},"5:2":{"text":"But thou, Bethlehem Ephratah, though thou be little among the thousands of Judah, yet out of thee shall he come forth unto me that is to be ruler in Israel; whose goings forth have been from of old, from everlasting.","words":[["H1035","But thou, Bethlehem",0,19],["H0672","Ephratah",20,28],["H6810","though thou be little",30,51],["H0505","among the thousands",52,71],["H3063","of Judah",72,80],["H3318","yet out of thee shall he come forth",82,117],["H4910","unto me that is to be ruler",118,145],["H3478","in Israel",146,155],["H4163","whose goings forth",157,175],["H6924","have been from of old",176,197],["H3117","from everlasting",199,215],["H5769","from everlasting",199,215]]},"5:3":{"text":"Therefore will he give them up, until the time that she which travaileth hath brought forth: then the remnant of his brethren shall return unto the children of Israel.","words":[["H5414","Therefore will he give them up",0,30],["H6256","until the time",32,46],["H3205","that she which travaileth",47,72],["H3205","hath brought forth",73,91],["H3499","then the remnant",93,109],["H0251","of his brethren",110,125],["H7725","shall return",126,138],["H1121","unto the children",139,156],["H3478","of Israel",157,166]]},"5:4":{"text":"And he shall stand and feed in the strength of the LORD, in the majesty of the name of the LORD his God; and they shall abide: for now shall he be great unto the ends of the earth.","words":[["H5975","And he shall stand",0,18],["H7462","and feed",19,27],["H5797","in the strength",28,43],["H3068","of the LORD",44,55],["H1347","in the majesty",57,71],["H8034","of the name",72,83],["H3068","of the LORD",84,95],["H0430","his God",96,103],["H3427","and they shall abide",105,125],["H1431","for now shall he be great",127,152],["H0657","unto the ends",153,166],["H0776","of the earth",167,179]]},"5:5":{"text":"And this man shall be the peace, when the Assyrian shall come into our land: and when he shall tread in our palaces, then shall we raise against him seven shepherds, and eight principal men.","words":[["H7965","And this man shall be the peace",0,31],["H0804","when the Assyrian",33,50],["H0935","shall come",51,61],["H0776","into our land",62,75],["H1869","and when he shall tread",77,100],["H0759","in our palaces",101,115],["H6965","then shall we raise",117,136],["H7651","against him seven",137,154],["H7462","shepherds",155,164],["H8083","and eight",166,175],["H5257","principal",176,185],["H0120","men",186,189]]},"5:6":{"text":"And they shall waste the land of Assyria with the sword, and the land of Nimrod in the entrances thereof: thus shall he deliver us from the Assyrian, when he cometh into our land, and when he treadeth within our borders.","words":[["H7462","And they shall waste",0,20],["H0776","the land",21,29],["H0804","of Assyria",30,40],["H2719","with the sword",41,55],["H0776","and the land",57,69],["H5248","of Nimrod",70,79],["H6607","in the entrances",80,96],["H5337","thereof: thus shall he deliver",97,127],["H0804","us from the Assyrian",128,148],["H0935","when he cometh",150,164],["H0776","into our land",165,178],["H1869","and when he treadeth",180,200],["H1366","within our borders",201,219]]},"5:7":{"text":"And the remnant of Jacob shall be in the midst of many people as a dew from the LORD, as the showers upon the grass, that tarrieth not for man, nor waiteth for the sons of men.","words":[["H7611","And the remnant",0,15],["H3290","of Jacob",16,24],["H7130","shall be in the midst",25,46],["H7227","of many",47,54],["H5971","people",55,61],["H2919","as a dew",62,70],["H3068","from the LORD",71,84],["H7241","as the showers",86,100],["H6212","upon the grass",101,115],["H6960","that tarrieth",117,130],["H0376","not for man",131,142],["H3176","nor waiteth",144,155],["H1121","for the sons",156,168],["H0120","of men",169,175]]},"5:8":{"text":"And the remnant of Jacob shall be among the Gentiles in the midst of many people as a lion among the beasts of the forest, as a young lion among the flocks of sheep: who, if he go through, both treadeth down, and teareth in pieces, and none can deliver.","words":[["H7611","And the remnant",0,15],["H3290","of Jacob",16,24],["H1471","shall be among the Gentiles",25,52],["H7130","in the midst",53,65],["H7227","of many",66,73],["H5971","people",74,80],["H0738","as a lion",81,90],["H0929","among the beasts",91,107],["H3293","of the forest",108,121],["H3715","as a young lion",123,138],["H5739","among the flocks",139,155],["H6629","of sheep",156,164],["H5674","who, if he go through",166,187],["H7429","both treadeth down",189,207],["H2963","and teareth in pieces",209,230],["H5337","and none can deliver",232,252]]},"5:9":{"text":"Thine hand shall be lifted up upon thine adversaries, and all thine enemies shall be cut off.","words":[["H3027","Thine hand",0,10],["H7311","shall be lifted up",11,29],["H6862","upon thine adversaries",30,52],["H0341","and all thine enemies",54,75],["H3772","shall be cut off",76,92]]},"5:10":{"text":"And it shall come to pass in that day, saith the LORD, that I will cut off thy horses out of the midst of thee, and I will destroy thy chariots:","words":[["H3117","And it shall come to pass in that day",0,37],["H5002","saith",39,44],["H3068","the LORD",45,53],["H3772","that I will cut off",55,74],["H5483","thy horses",75,85],["H7130","out of the midst",86,102],["H0006","of thee, and I will destroy",103,130],["H4818","thy chariots",131,143]]},"5:11":{"text":"And I will cut off the cities of thy land, and throw down all thy strong holds:","words":[["H3772","And I will cut off",0,18],["H6145","the cities",19,29],["H5892","the cities",19,29],["H0776","of thy land",30,41],["H2040","and throw down",43,57],["H4013","all thy strong holds",58,78]]},"5:12":{"text":"And I will cut off witchcrafts out of thine hand; and thou shalt have no more soothsayers:","words":[["H3772","And I will cut off",0,18],["H3785","witchcrafts",19,30],["H3027","out of thine hand",31,48],["H6049","and thou shalt have no more soothsayers",50,89]]},"5:13":{"text":"Thy graven images also will I cut off, and thy standing images out of the midst of thee; and thou shalt no more worship the work of thine hands.","words":[["H6456","Thy graven images",0,17],["H3772","also will I cut off",18,37],["H4676","and thy standing images",39,62],["H7130","out of the midst",63,79],["H7812","of thee; and thou shalt no more worship",80,119],["H4639","the work",120,128],["H3027","of thine hands",129,143]]},"5:14":{"text":"And I will pluck up thy groves out of the midst of thee: so will I destroy thy cities.","words":[["H5428","And I will pluck up",0,19],["H0842","thy groves",20,30],["H7130","out of the midst",31,47],["H8045","of thee: so will I destroy",48,74],["H6145","thy cities",75,85],["H5892","thy cities",75,85]]},"5:15":{"text":"And I will execute vengeance in anger and fury upon the heathen, such as they have not heard.","words":[["H6213","And I will execute",0,18],["H5359","vengeance",19,28],["H0639","in anger",29,37],["H2534","and fury",38,46],["H1471","upon the heathen",47,63],["H8085","such as they have not heard",65,92]]},"6:1":{"text":"Hear ye now what the LORD saith; Arise, contend thou before the mountains, and let the hills hear thy voice.","words":[["H8085","Hear",0,4],["H3068","ye now what the LORD",5,25],["H0559","saith",26,31],["H6965","Arise",33,38],["H7378","contend",40,47],["H2022","thou before the mountains",48,73],["H1389","and let the hills",75,92],["H8085","hear",93,97],["H6963","thy voice",98,107]]},"6:2":{"text":"Hear ye, O mountains, the LORD'S controversy, and ye strong foundations of the earth: for the LORD hath a controversy with his people, and he will plead with Israel.","words":[["H8085","Hear",0,4],["H2022","ye, O mountains",5,20],["H3068","the LORD'S",22,32],["H7379","controversy",33,44],["H0386","and ye strong",46,59],["H4146","foundations",60,71],["H0776","of the earth",72,84],["H3068","for the LORD",86,98],["H7379","hath a controversy",99,117],["H5971","with his people",118,133],["H3198","and he will plead",135,152],["H3478","with Israel",153,164]]},"6:3":{"text":"O my people, what have I done unto thee? and wherein have I wearied thee? testify against me.","words":[["H5971","O my people",0,11],["H6213","what have I done",13,29],["H3811","unto thee? and wherein have I wearied",30,67],["H6030","thee? testify",68,81]]},"6:4":{"text":"For I brought thee up out of the land of Egypt, and redeemed thee out of the house of servants; and I sent before thee Moses, Aaron, and Miriam.","words":[["H5927","For I brought thee up",0,21],["H0776","out of the land",22,37],["H4714","of Egypt",38,46],["H6299","and redeemed",48,60],["H1004","thee out of the house",61,82],["H5650","of servants",83,94],["H7971","and I sent",96,106],["H6440","before",107,113],["H4872","thee Moses",114,124],["H0175","Aaron",126,131],["H4813","and Miriam",133,143]]},"6:5":{"text":"O my people, remember now what Balak king of Moab consulted, and what Balaam the son of Beor answered him from Shittim unto Gilgal; that ye may know the righteousness of the LORD.","words":[["H5971","O my people",0,11],["H2142","remember",13,21],["H1111","now what Balak",22,36],["H4428","king",37,41],["H4124","of Moab",42,49],["H3289","consulted",50,59],["H1109","and what Balaam",61,76],["H1121","the son",77,84],["H1160","of Beor",85,92],["H6030","answered",93,101],["H7851","him from Shittim",102,118],["H1537","unto Gilgal",119,130],["H3045","that ye may know",132,148],["H6666","the righteousness",149,166],["H3068","of the LORD",167,178]]},"6:6":{"text":"Wherewith shall I come before the LORD, and bow myself before the high God? shall I come before him with burnt offerings, with calves of a year old?","words":[["H6923","Wherewith shall I come before",0,29],["H3068","the LORD",30,38],["H3721","and bow",40,47],["H4791","myself before the high",48,70],["H0430","God",71,74],["H6923","shall I come before",76,95],["H5930","him with burnt offerings",96,120],["H5695","with calves",122,133],["H8141","of a year",134,143],["H1121","old",144,147]]},"6:7":{"text":"Will the LORD be pleased with thousands of rams, or with ten thousands of rivers of oil? shall I give my firstborn for my transgression, the fruit of my body for the sin of my soul?","words":[["H3068","Will the LORD",0,13],["H7521","be pleased",14,24],["H0505","with thousands",25,39],["H0352","of rams",40,47],["H7233","or with ten thousands",49,70],["H5158","of rivers",71,80],["H8081","of oil",81,87],["H5414","shall I give",89,101],["H1060","my firstborn",102,114],["H6588","for my transgression",115,135],["H6529","the fruit",137,146],["H0990","of my body",147,157],["H2403","for the sin",158,169],["H5315","of my soul",170,180]]},"6:8":{"text":"He hath shewed thee, O man, what is good; and what doth the LORD require of thee, but to do justly, and to love mercy, and to walk humbly with thy God?","words":[["H5046","He hath shewed",0,14],["H0120","thee, O man",15,26],["H2896","what is good",28,40],["H3068","and what doth the LORD",42,64],["H1875","require",65,72],["H6213","of thee, but to do",73,91],["H4941","justly",92,98],["H0160","and to love",100,111],["H2617","mercy",112,117],["H3212","and to walk",119,130],["H6800","humbly",131,137],["H0430","with thy God",138,150]]},"6:9":{"text":"The LORD'S voice crieth unto the city, and the man of wisdom shall see thy name: hear ye the rod, and who hath appointed it.","words":[["H3068","The LORD'S",0,10],["H6963","voice",11,16],["H7121","crieth",17,23],["H5892","unto the city",24,37],["H8454","and the man of wisdom",39,60],["H7200","shall see",61,70],["H8034","thy name",71,79],["H8085","hear",81,85],["H4294","ye the rod",86,96],["H3259","and who hath appointed",98,120]]},"6:10":{"text":"Are there yet the treasures of wickedness in the house of the wicked, and the scant measure that is abominable?","words":[["H0786","Are there",0,9],["H0214","yet the treasures",10,27],["H7562","of wickedness",28,41],["H0376","of wickedness",28,41],["H1004","in the house",42,54],["H7563","of the wicked",55,68],["H7332","and the scant",70,83],["H0374","measure",84,91],["H2194","that is abominable",92,110]]},"6:11":{"text":"Shall I count them pure with the wicked balances, and with the bag of deceitful weights?","words":[["H2135","Shall I count them pure",0,23],["H7562","with the wicked",24,39],["H3976","balances",40,48],["H3599","and with the bag",50,66],["H4820","of deceitful",67,79],["H0068","weights",80,87]]},"6:12":{"text":"For the rich men thereof are full of violence, and the inhabitants thereof have spoken lies, and their tongue is deceitful in their mouth.","words":[["H6223","For the rich men",0,16],["H4390","thereof are full",17,33],["H2555","of violence",34,45],["H3427","and the inhabitants",47,66],["H1696","thereof have spoken",67,86],["H8267","lies",87,91],["H3956","and their tongue",93,109],["H7423","is deceitful",110,122],["H6310","in their mouth",123,137]]},"6:13":{"text":"Therefore also will I make thee sick in smiting thee, in making thee desolate because of thy sins.","words":[["H2470","Therefore also will I make thee sick",0,36],["H5221","in smiting",37,47],["H8074","thee, in making thee desolate",48,77],["H2403","because of thy sins",78,97]]},"6:14":{"text":"Thou shalt eat, but not be satisfied; and thy casting down shall be in the midst of thee; and thou shalt take hold, but shalt not deliver; and that which thou deliverest will I give up to the sword.","words":[["H0398","Thou shalt eat",0,14],["H7646","but not be satisfied",16,36],["H3445","and thy casting down",38,58],["H7130","shall be in the midst",59,80],["H5253","of thee; and thou shalt take hold",81,114],["H6403","but shalt not deliver",116,137],["H6403","and that which thou deliverest",139,169],["H5414","will I give up",170,184],["H2719","to the sword",185,197]]},"6:15":{"text":"Thou shalt sow, but thou shalt not reap; thou shalt tread the olives, but thou shalt not anoint thee with oil; and sweet wine, but shalt not drink wine.","words":[["H2232","Thou shalt sow",0,14],["H7114","but thou shalt not reap",16,39],["H1869","thou shalt tread",41,57],["H2132","the olives",58,68],["H5480","but thou shalt not anoint",70,95],["H8081","thee with oil",96,109],["H8492","and sweet wine",111,125],["H8354","but shalt not drink",127,146],["H3196","wine",147,151]]},"6:16":{"text":"For the statutes of Omri are kept, and all the works of the house of Ahab, and ye walk in their counsels; that I should make thee a desolation, and the inhabitants thereof an hissing: therefore ye shall bear the reproach of my people.","words":[["H2708","For the statutes",0,16],["H6018","of Omri",17,24],["H8104","are kept",25,33],["H4639","and all the works",35,52],["H1004","of the house",53,65],["H0256","of Ahab",66,73],["H3212","and ye walk",75,86],["H4156","in their counsels",87,104],["H5414","that I should make",106,124],["H8047","thee a desolation",125,142],["H3427","and the inhabitants",144,163],["H8322","thereof an hissing",164,182],["H5375","therefore ye shall bear",184,207],["H2781","the reproach",208,220],["H5971","of my people",221,233]]},"7:1":{"text":"Woe is me! for I am as when they have gathered the summer fruits, as the grapegleanings of the vintage: there is no cluster to eat: my soul desired the firstripe fruit.","words":[["H0480","Woe",0,3],["H0625","is me! for I am as when they have gathered",4,46],["H7019","the summer fruits",47,64],["H5955","as the grapegleanings",66,87],["H1210","of the vintage",88,102],["H0811","there is no cluster",104,123],["H0398","to eat",124,130],["H5315","my soul",132,139],["H0183","desired",140,147],["H1063","the firstripe fruit",148,167]]},"7:2":{"text":"The good man is perished out of the earth: and there is none upright among men: they all lie in wait for blood; they hunt every man his brother with a net.","words":[["H2623","The good",0,8],["H0006","man is perished",9,24],["H0776","out of the earth",25,41],["H3477","and there is none upright",43,68],["H0120","among men",69,78],["H0693","they all lie in wait",80,100],["H1818","for blood",101,110],["H6679","they hunt",112,121],["H0376","every man",122,131],["H0251","his brother",132,143],["H2764","with a net",144,154]]},"7:3":{"text":"That they may do evil with both hands earnestly, the prince asketh, and the judge asketh for a reward; and the great man, he uttereth his mischievous desire: so they wrap it up.","words":[["H7451","That they may do evil",0,21],["H3709","with both hands",22,37],["H3190","earnestly",38,47],["H8269","the prince",49,59],["H7592","asketh",60,66],["H8199","and the judge",68,81],["H7966","asketh for a reward",82,101],["H1419","and the great",103,116],["H1696","man, he uttereth",117,133],["H1942","his mischievous",134,149],["H5315","desire",150,156],["H5686","so they wrap it up",158,176]]},"7:4":{"text":"The best of them is as a brier: the most upright is sharper than a thorn hedge: the day of thy watchmen and thy visitation cometh; now shall be their perplexity.","words":[["H2896","The best",0,8],["H2312","of them is as a brier",9,30],["H3477","the most upright",32,48],["H4534","is sharper than a thorn hedge",49,78],["H3117","the day",80,87],["H6822","of thy watchmen",88,103],["H6486","and thy visitation",104,122],["H0935","cometh",123,129],["H3998","now shall be their perplexity",131,160]]},"7:5":{"text":"Trust ye not in a friend, put ye not confidence in a guide: keep the doors of thy mouth from her that lieth in thy bosom.","words":[["H0539","Trust",0,5],["H7453","ye not in a friend",6,24],["H0982","put ye not confidence",26,47],["H0441","in a guide",48,58],["H8104","keep",60,64],["H6607","the doors",65,74],["H6310","of thy mouth",75,87],["H7901","from her that lieth",88,107],["H2436","in thy bosom",108,120]]},"7:6":{"text":"For the son dishonoureth the father, the daughter riseth up against her mother, the daughter in law against her mother in law; a man's enemies are the men of his own house.","words":[["H1121","For the son",0,11],["H5034","dishonoureth",12,24],["H0001","the father",25,35],["H1323","the daughter",37,49],["H6965","riseth up",50,59],["H0517","against her mother",60,78],["H3618","the daughter in law",80,99],["H2545","against her mother in law",100,125],["H0376","a man's",127,134],["H0341","enemies",135,142],["H0582","are the men",143,154],["H1004","of his own house",155,171]]},"7:7":{"text":"Therefore I will look unto the LORD; I will wait for the God of my salvation: my God will hear me.","words":[["H6822","Therefore I will look",0,21],["H3068","unto the LORD",22,35],["H3176","I will wait",37,48],["H0430","for the God",49,60],["H3468","of my salvation",61,76],["H0430","my God",78,84],["H8085","will hear",85,94]]},"7:8":{"text":"Rejoice not against me, O mine enemy: when I fall, I shall arise; when I sit in darkness, the LORD shall be a light unto me.","words":[["H8055","Rejoice",0,7],["H0341","not against me, O mine enemy",8,36],["H5307","when I fall",38,49],["H6965","I shall arise",51,64],["H3427","when I sit",66,76],["H2822","in darkness",77,88],["H3068","the LORD",90,98],["H0216","shall be a light",99,115]]},"7:9":{"text":"I will bear the indignation of the LORD, because I have sinned against him, until he plead my cause, and execute judgment for me: he will bring me forth to the light, and I shall behold his righteousness.","words":[["H5375","I will bear",0,11],["H2197","the indignation",12,27],["H3068","of the LORD",28,39],["H2398","because I have sinned",41,62],["H7378","against him, until he plead",63,90],["H7379","my cause",91,99],["H6213","and execute",101,112],["H4941","judgment",113,121],["H3318","for me: he will bring me forth",122,152],["H0216","to the light",153,165],["H7200","and I shall behold",167,185],["H6666","his righteousness",186,203]]},"7:10":{"text":"Then she that is mine enemy shall see it, and shame shall cover her which said unto me, Where is the LORD thy God? mine eyes shall behold her: now shall she be trodden down as the mire of the streets.","words":[["H0341","Then she that is mine enemy",0,27],["H7200","shall see",28,37],["H0955","it, and shame",38,51],["H3680","shall cover",52,63],["H0559","her which said",64,78],["H3068","unto me, Where is the LORD",79,105],["H0430","thy God",106,113],["H5869","mine eyes",115,124],["H7200","shall behold",125,137],["H4823","her: now shall she be trodden down",138,172],["H2916","as the mire",173,184],["H2351","of the streets",185,199]]},"7:11":{"text":"In the day that thy walls are to be built, in that day shall the decree be far removed.","words":[["H3117","In the day",0,10],["H1447","that thy walls",11,25],["H1129","are to be built",26,41],["H3117","in that day",43,54],["H2706","shall the decree",55,71],["H7368","be far removed",72,86]]},"7:12":{"text":"In that day also he shall come even to thee from Assyria, and from the fortified cities, and from the fortress even to the river, and from sea to sea, and from mountain to mountain.","words":[["H3117","In that day",0,11],["H0935","also he shall come",12,30],["H0804","even to thee from Assyria",31,56],["H4693","and from the fortified",58,80],["H5892","cities",81,87],["H4693","and from the fortress",89,110],["H5104","even to the river",111,128],["H3220","and from sea",130,142],["H3220","to sea",143,149],["H2022","and from mountain",151,168],["H2022","to mountain",169,180]]},"7:13":{"text":"Notwithstanding the land shall be desolate because of them that dwell therein, for the fruit of their doings.","words":[["H0776","Notwithstanding the land",0,24],["H8077","shall be desolate",25,42],["H3427","because of them that dwell",43,69],["H6529","therein, for the fruit",70,92],["H4611","of their doings",93,108]]},"7:14":{"text":"Feed thy people with thy rod, the flock of thine heritage, which dwell solitarily in the wood, in the midst of Carmel: let them feed in Bashan and Gilead, as in the days of old.","words":[["H7462","Feed",0,4],["H5971","thy people",5,15],["H7626","with thy rod",16,28],["H6629","the flock",30,39],["H5159","of thine heritage",40,57],["H7931","which dwell",59,70],["H0910","solitarily",71,81],["H3293","in the wood",82,93],["H8432","in the midst",95,107],["H3760","of Carmel",108,117],["H7462","let them feed",119,132],["H1316","in Bashan",133,142],["H1568","and Gilead",143,153],["H3117","as in the days",155,169],["H5769","of old",170,176]]},"7:15":{"text":"According to the days of thy coming out of the land of Egypt will I shew unto him marvellous things.","words":[["H3117","According to the days",0,21],["H3318","of thy coming",22,35],["H0776","out of the land",36,51],["H4714","of Egypt",52,60],["H7200","will I shew",61,72],["H6381","unto him marvellous",73,92]]},"7:16":{"text":"The nations shall see and be confounded at all their might: they shall lay their hand upon their mouth, their ears shall be deaf.","words":[["H1471","The nations",0,11],["H7200","shall see",12,21],["H0954","and be confounded",22,39],["H1369","at all their might",40,58],["H7760","they shall lay",60,74],["H3027","their hand",75,85],["H6310","upon their mouth",86,102],["H0241","their ears",104,114],["H2790","shall be deaf",115,128]]},"7:17":{"text":"They shall lick the dust like a serpent, they shall move out of their holes like worms of the earth: they shall be afraid of the LORD our God, and shall fear because of thee.","words":[["H3897","They shall lick",0,15],["H6083","the dust",16,24],["H5175","like a serpent",25,39],["H7264","they shall move",41,56],["H4526","out of their holes",57,75],["H2119","like worms",76,86],["H0776","of the earth",87,99],["H6342","they shall be afraid",101,121],["H3068","of the LORD",122,133],["H0430","our God",134,141],["H3372","and shall fear",143,157]]},"7:18":{"text":"Who is a God like unto thee, that pardoneth iniquity, and passeth by the transgression of the remnant of his heritage? he retaineth not his anger for ever, because he delighteth in mercy.","words":[["H0410","Who is a God",0,12],["H5375","like unto thee, that pardoneth",13,43],["H5771","iniquity",44,52],["H5674","and passeth by",54,68],["H6588","the transgression",69,86],["H7611","of the remnant",87,101],["H5159","of his heritage",102,117],["H2388","he retaineth",119,131],["H0639","not his anger",132,145],["H5703","for ever",146,154],["H2654","because he delighteth",156,177],["H2617","in mercy",178,186]]},"7:19":{"text":"He will turn again, he will have compassion upon us; he will subdue our iniquities; and thou wilt cast all their sins into the depths of the sea.","words":[["H7725","He will turn again",0,18],["H7355","he will have compassion",20,43],["H3533","upon us; he will subdue",44,67],["H5771","our iniquities",68,82],["H7993","and thou wilt cast",84,102],["H2403","all their sins",103,117],["H4688","into the depths",118,133],["H3220","of the sea",134,144]]},"7:20":{"text":"Thou wilt perform the truth to Jacob, and the mercy to Abraham, which thou hast sworn unto our fathers from the days of old.","words":[["H5414","Thou wilt perform",0,17],["H0571","the truth",18,27],["H3290","to Jacob",28,36],["H2617","and the mercy",38,51],["H0085","to Abraham",52,62],["H7650","which thou hast sworn",64,85],["H0001","unto our fathers",86,102],["H3117","from the days",103,116],["H6924","of old",117,123]]}}};
